import { describe, it, expect } from 'vitest'
import {
  calculateOrderTotal,
  deriveOrderStatus,
} from '../order-status'
import type { ItemStatus } from '../order-status'

// ─── calculateOrderTotal with newly added items ─────────────────────

describe('calculateOrderTotal — add-item scenarios', () => {
  it('includes newly added PENDING items in total', () => {
    // Existing items (already being prepared) + new items (PENDING)
    const items = [
      { status: 'PREPARING', price: 35000, quantity: 1 }, // existing: 35000
      { status: 'READY', price: 25000, quantity: 2 },     // existing: 50000
      { status: 'PENDING', price: 40000, quantity: 1 },   // new: 40000
      { status: 'PENDING', price: 15000, quantity: 3 },   // new: 45000
    ]
    expect(calculateOrderTotal(items)).toBe(170000)
  })

  it('excludes CANCELLED items but includes new PENDING items', () => {
    const items = [
      { status: 'CANCELLED', price: 30000, quantity: 1 }, // excluded
      { status: 'SERVED', price: 20000, quantity: 2 },    // existing: 40000
      { status: 'PENDING', price: 50000, quantity: 1 },   // new: 50000
    ]
    expect(calculateOrderTotal(items)).toBe(90000)
  })

  it('computes correct total when all existing items are CANCELLED and new ones are added', () => {
    // Edge case: everything was cancelled, then staff adds new items
    const items = [
      { status: 'CANCELLED', price: 30000, quantity: 2 }, // excluded
      { status: 'CANCELLED', price: 25000, quantity: 1 }, // excluded
      { status: 'PENDING', price: 45000, quantity: 1 },   // new: 45000
    ]
    expect(calculateOrderTotal(items)).toBe(45000)
  })

  it('handles single newly added item on empty order', () => {
    const items = [
      { status: 'PENDING', price: 29000, quantity: 2 },   // new: 58000
    ]
    expect(calculateOrderTotal(items)).toBe(58000)
  })

  it('handles large VND values without overflow', () => {
    // VND prices can be large integers
    const items = [
      { status: 'PENDING', price: 150000, quantity: 10 },  // 1,500,000
      { status: 'PREPARING', price: 250000, quantity: 5 }, // 1,250,000
    ]
    expect(calculateOrderTotal(items)).toBe(2750000)
  })
})

// ─── deriveOrderStatus after adding PENDING items ───────────────────

describe('deriveOrderStatus — add-item scenarios', () => {
  it('returns PREPARING when adding PENDING items to order with PREPARING items', () => {
    // Existing: some PREPARING, newly added: PENDING
    const statuses: ItemStatus[] = ['PREPARING', 'PREPARING', 'PENDING', 'PENDING']
    expect(deriveOrderStatus(statuses)).toBe('PREPARING')
  })

  it('returns PREPARING when adding PENDING items to order with READY items', () => {
    // Existing items are READY, but new PENDING items bring status back
    const statuses: ItemStatus[] = ['READY', 'READY', 'PENDING']
    expect(deriveOrderStatus(statuses)).toBe('PREPARING')
  })

  it('returns PREPARING when adding PENDING items to order with SERVED items', () => {
    // Existing items fully SERVED, new items are PENDING
    const statuses: ItemStatus[] = ['SERVED', 'SERVED', 'PENDING']
    expect(deriveOrderStatus(statuses)).toBe('PREPARING')
  })

  it('returns PREPARING when adding PENDING to mixed READY/SERVED/CANCELLED order', () => {
    const statuses: ItemStatus[] = ['READY', 'SERVED', 'CANCELLED', 'PENDING']
    expect(deriveOrderStatus(statuses)).toBe('PREPARING')
  })

  it('returns PENDING when adding PENDING items to all-CANCELLED order', () => {
    // All existing items were cancelled, new items are PENDING → order is PENDING
    const statuses: ItemStatus[] = ['CANCELLED', 'CANCELLED', 'PENDING']
    expect(deriveOrderStatus(statuses)).toBe('PENDING')
  })

  it('returns PENDING when single new PENDING item added to empty-like order', () => {
    const statuses: ItemStatus[] = ['PENDING']
    expect(deriveOrderStatus(statuses)).toBe('PENDING')
  })
})

// ─── PAID guard logic ───────────────────────────────────────────────

describe('PAID guard — add-item rejection logic', () => {
  it('order with PAID status should be rejected for item addition', () => {
    // Simulates the guard check: if order.status === 'PAID', reject
    const orderStatus = 'PAID'
    expect(orderStatus === 'PAID').toBe(true)
  })

  it('order with non-PAID status should be allowed for item addition', () => {
    const allowedStatuses = ['PENDING', 'PREPARING', 'READY', 'SERVED', 'CANCELLED']
    for (const status of allowedStatuses) {
      expect(status === 'PAID').toBe(false)
    }
  })

  it('PAID is a terminal state — deriveOrderStatus never returns PAID', () => {
    // PAID is set by the payment flow, not derived from item statuses.
    // Verify that no combination of item statuses produces PAID.
    const allCombos: ItemStatus[][] = [
      ['PENDING'],
      ['PREPARING'],
      ['READY'],
      ['SERVED'],
      ['CANCELLED'],
      ['PENDING', 'PREPARING', 'READY', 'SERVED', 'CANCELLED'],
      [],
    ]
    for (const combo of allCombos) {
      expect(deriveOrderStatus(combo)).not.toBe('PAID')
    }
  })
})

import { describe, it, expect } from 'vitest'
import {
  deriveOrderStatus,
  isValidTransition,
  getValidNextStatuses,
} from '../order-status'
import type { ItemStatus } from '../order-status'

// ─── deriveOrderStatus ──────────────────────────────────────────────

describe('deriveOrderStatus', () => {
  it('returns PENDING for empty array', () => {
    expect(deriveOrderStatus([])).toBe('PENDING')
  })

  it('returns PENDING when all items are PENDING', () => {
    expect(deriveOrderStatus(['PENDING', 'PENDING', 'PENDING'])).toBe(
      'PENDING'
    )
  })

  it('returns PREPARING when any item is PREPARING', () => {
    expect(deriveOrderStatus(['PENDING', 'PREPARING'])).toBe('PREPARING')
  })

  it('returns PREPARING when mix of PREPARING and READY', () => {
    expect(deriveOrderStatus(['PREPARING', 'READY'])).toBe('PREPARING')
  })

  it('returns PREPARING when PENDING + READY (some still behind)', () => {
    // PENDING items haven't started, but READY items have been through PREPARING
    // The order is still "in progress" → PREPARING
    expect(deriveOrderStatus(['PENDING', 'READY'])).toBe('PREPARING')
  })

  it('returns READY when all non-cancelled items are READY', () => {
    expect(deriveOrderStatus(['READY', 'READY'])).toBe('READY')
  })

  it('returns READY when mix of READY and CANCELLED', () => {
    expect(deriveOrderStatus(['READY', 'CANCELLED', 'READY'])).toBe('READY')
  })

  it('returns READY when mix of READY and SERVED', () => {
    expect(deriveOrderStatus(['READY', 'SERVED'])).toBe('READY')
  })

  it('returns SERVED when all non-cancelled items are SERVED', () => {
    expect(deriveOrderStatus(['SERVED', 'SERVED'])).toBe('SERVED')
  })

  it('returns SERVED when mix of SERVED and CANCELLED', () => {
    expect(deriveOrderStatus(['SERVED', 'CANCELLED'])).toBe('SERVED')
  })

  it('returns CANCELLED when all items are CANCELLED', () => {
    expect(deriveOrderStatus(['CANCELLED', 'CANCELLED'])).toBe('CANCELLED')
  })

  it('returns CANCELLED for single CANCELLED item', () => {
    expect(deriveOrderStatus(['CANCELLED'])).toBe('CANCELLED')
  })

  // Complex mixed scenarios
  it('returns PREPARING for mixed bag: PENDING + PREPARING + CANCELLED', () => {
    expect(
      deriveOrderStatus(['PENDING', 'PREPARING', 'CANCELLED'])
    ).toBe('PREPARING')
  })

  it('returns PREPARING for: PENDING + READY + SERVED + CANCELLED', () => {
    expect(
      deriveOrderStatus(['PENDING', 'READY', 'SERVED', 'CANCELLED'])
    ).toBe('PREPARING')
  })

  it('returns READY for: READY + SERVED + CANCELLED', () => {
    expect(
      deriveOrderStatus(['READY', 'SERVED', 'CANCELLED'])
    ).toBe('READY')
  })

  it('handles single PENDING item', () => {
    expect(deriveOrderStatus(['PENDING'])).toBe('PENDING')
  })

  it('handles single PREPARING item', () => {
    expect(deriveOrderStatus(['PREPARING'])).toBe('PREPARING')
  })

  it('handles single READY item', () => {
    expect(deriveOrderStatus(['READY'])).toBe('READY')
  })

  it('handles single SERVED item', () => {
    expect(deriveOrderStatus(['SERVED'])).toBe('SERVED')
  })
})

// ─── isValidTransition ──────────────────────────────────────────────

describe('isValidTransition', () => {
  // Forward transitions
  it('allows PENDING → PREPARING', () => {
    expect(isValidTransition('PENDING', 'PREPARING')).toBe(true)
  })

  it('allows PREPARING → READY', () => {
    expect(isValidTransition('PREPARING', 'READY')).toBe(true)
  })

  it('allows READY → SERVED', () => {
    expect(isValidTransition('READY', 'SERVED')).toBe(true)
  })

  // Cancellation from any state
  it('allows PENDING → CANCELLED', () => {
    expect(isValidTransition('PENDING', 'CANCELLED')).toBe(true)
  })

  it('allows PREPARING → CANCELLED', () => {
    expect(isValidTransition('PREPARING', 'CANCELLED')).toBe(true)
  })

  it('allows READY → CANCELLED', () => {
    expect(isValidTransition('READY', 'CANCELLED')).toBe(true)
  })

  it('allows SERVED → CANCELLED', () => {
    expect(isValidTransition('SERVED', 'CANCELLED')).toBe(true)
  })

  // Backward transitions (must be rejected)
  it('rejects PREPARING → PENDING (backward)', () => {
    expect(isValidTransition('PREPARING', 'PENDING')).toBe(false)
  })

  it('rejects READY → PREPARING (backward)', () => {
    expect(isValidTransition('READY', 'PREPARING')).toBe(false)
  })

  it('rejects SERVED → READY (backward)', () => {
    expect(isValidTransition('SERVED', 'READY')).toBe(false)
  })

  it('rejects READY → PENDING (skip backward)', () => {
    expect(isValidTransition('READY', 'PENDING')).toBe(false)
  })

  // Skip-forward transitions (must be rejected)
  it('rejects PENDING → READY (skip forward)', () => {
    expect(isValidTransition('PENDING', 'READY')).toBe(false)
  })

  it('rejects PENDING → SERVED (skip forward)', () => {
    expect(isValidTransition('PENDING', 'SERVED')).toBe(false)
  })

  it('rejects PREPARING → SERVED (skip forward)', () => {
    expect(isValidTransition('PREPARING', 'SERVED')).toBe(false)
  })

  // No-op transitions (same → same)
  it('rejects PENDING → PENDING (no-op)', () => {
    expect(isValidTransition('PENDING', 'PENDING')).toBe(false)
  })

  it('rejects PREPARING → PREPARING (no-op)', () => {
    expect(isValidTransition('PREPARING', 'PREPARING')).toBe(false)
  })

  // CANCELLED is terminal
  it('rejects CANCELLED → PENDING', () => {
    expect(isValidTransition('CANCELLED', 'PENDING')).toBe(false)
  })

  it('rejects CANCELLED → PREPARING', () => {
    expect(isValidTransition('CANCELLED', 'PREPARING')).toBe(false)
  })

  it('rejects CANCELLED → CANCELLED', () => {
    expect(isValidTransition('CANCELLED', 'CANCELLED')).toBe(false)
  })
})

// ─── getValidNextStatuses ───────────────────────────────────────────

describe('getValidNextStatuses', () => {
  it('returns [PREPARING, CANCELLED] for PENDING', () => {
    expect(getValidNextStatuses('PENDING')).toEqual(['PREPARING', 'CANCELLED'])
  })

  it('returns [READY, CANCELLED] for PREPARING', () => {
    expect(getValidNextStatuses('PREPARING')).toEqual(['READY', 'CANCELLED'])
  })

  it('returns [SERVED, CANCELLED] for READY', () => {
    expect(getValidNextStatuses('READY')).toEqual(['SERVED', 'CANCELLED'])
  })

  it('returns [CANCELLED] for SERVED', () => {
    expect(getValidNextStatuses('SERVED')).toEqual(['CANCELLED'])
  })

  it('returns empty array for CANCELLED (terminal)', () => {
    expect(getValidNextStatuses('CANCELLED')).toEqual([])
  })
})

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

/**
 * GET /api/admin/menu
 *
 * Returns ALL menu items (including hidden), ordered by sortOrder.
 * Admin middleware handles authentication.
 */
export async function GET() {
  try {
    const items = await prisma.menuItem.findMany({
      orderBy: { sortOrder: 'asc' },
    })

    console.log(`[GET /api/admin/menu] Returning ${items.length} menu items (including hidden)`)

    return NextResponse.json({ items })
  } catch (error) {
    console.error('[GET /api/admin/menu] Failed to fetch menu items:', error)
    return NextResponse.json(
      { error: 'Không thể tải danh sách món. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * POST /api/admin/menu
 *
 * Creates a new menu item.
 * Required: name (string), price (int > 0), category (DRINK | FOOD).
 * Optional: description (string), sortOrder (int), available (boolean).
 */
export async function POST(request: NextRequest) {
  let body: Record<string, unknown>
  try {
    body = await request.json()
  } catch {
    return NextResponse.json(
      { error: 'Dữ liệu không hợp lệ.' },
      { status: 400 },
    )
  }

  const { name, price, category, description, sortOrder, available } = body

  // --- Validate required fields ---
  if (!name || typeof name !== 'string' || name.trim().length === 0) {
    return NextResponse.json(
      { error: 'Tên món không được để trống' },
      { status: 400 },
    )
  }

  if (typeof price !== 'number' || !Number.isInteger(price) || price <= 0) {
    return NextResponse.json(
      { error: 'Giá phải lớn hơn 0' },
      { status: 400 },
    )
  }

  if (category !== 'DRINK' && category !== 'FOOD') {
    return NextResponse.json(
      { error: 'Danh mục phải là DRINK hoặc FOOD' },
      { status: 400 },
    )
  }

  try {
    const item = await prisma.menuItem.create({
      data: {
        name: name.trim(),
        price,
        category,
        description: typeof description === 'string' ? description.trim() : null,
        sortOrder: typeof sortOrder === 'number' && Number.isInteger(sortOrder) ? sortOrder : 0,
        available: typeof available === 'boolean' ? available : true,
      },
    })

    console.log(`[POST /api/admin/menu] Created menu item #${item.id}: ${item.name}`)

    return NextResponse.json({ item }, { status: 201 })
  } catch (error) {
    console.error('[POST /api/admin/menu] Failed to create menu item:', error)
    return NextResponse.json(
      { error: 'Không thể tạo món mới. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

type RouteContext = { params: Promise<{ id: string }> }

/**
 * PUT /api/admin/menu/[id]
 *
 * Full update of a menu item. Any combination of fields can be provided.
 */
export async function PUT(request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)
  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID không hợp lệ' }, { status: 400 })
  }

  let body: Record<string, unknown>
  try {
    body = await request.json()
  } catch {
    return NextResponse.json(
      { error: 'Dữ liệu không hợp lệ.' },
      { status: 400 },
    )
  }

  // Check item exists
  const existing = await prisma.menuItem.findUnique({ where: { id } })
  if (!existing) {
    return NextResponse.json({ error: 'Món không tồn tại' }, { status: 404 })
  }

  // Build update data from provided fields
  const data: Record<string, unknown> = {}

  if (body.name !== undefined) {
    if (typeof body.name !== 'string' || body.name.trim().length === 0) {
      return NextResponse.json({ error: 'Tên món không được để trống' }, { status: 400 })
    }
    data.name = body.name.trim()
  }

  if (body.price !== undefined) {
    if (typeof body.price !== 'number' || !Number.isInteger(body.price) || body.price <= 0) {
      return NextResponse.json({ error: 'Giá phải lớn hơn 0' }, { status: 400 })
    }
    data.price = body.price
  }

  if (body.category !== undefined) {
    if (body.category !== 'DRINK' && body.category !== 'FOOD') {
      return NextResponse.json({ error: 'Danh mục phải là DRINK hoặc FOOD' }, { status: 400 })
    }
    data.category = body.category
  }

  if (body.description !== undefined) {
    data.description = typeof body.description === 'string' ? body.description.trim() : null
  }

  if (body.sortOrder !== undefined) {
    if (typeof body.sortOrder !== 'number' || !Number.isInteger(body.sortOrder)) {
      return NextResponse.json({ error: 'Thứ tự phải là số nguyên' }, { status: 400 })
    }
    data.sortOrder = body.sortOrder
  }

  if (body.available !== undefined) {
    if (typeof body.available !== 'boolean') {
      return NextResponse.json({ error: 'Trạng thái phải là boolean' }, { status: 400 })
    }
    data.available = body.available
  }

  try {
    const item = await prisma.menuItem.update({ where: { id }, data })
    console.log(`[PUT /api/admin/menu/${id}] Updated menu item: ${item.name}`)
    return NextResponse.json({ item })
  } catch (error) {
    console.error(`[PUT /api/admin/menu/${id}] Failed to update:`, error)
    return NextResponse.json(
      { error: 'Không thể cập nhật món. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * PATCH /api/admin/menu/[id]
 *
 * Toggle a boolean field: available or hidden.
 * Body: { field: 'available' | 'hidden', value: boolean }
 */
export async function PATCH(request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)
  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID không hợp lệ' }, { status: 400 })
  }

  let body: Record<string, unknown>
  try {
    body = await request.json()
  } catch {
    return NextResponse.json(
      { error: 'Dữ liệu không hợp lệ.' },
      { status: 400 },
    )
  }

  const { field, value } = body

  if ((field !== 'available' && field !== 'hidden') || typeof value !== 'boolean') {
    return NextResponse.json(
      { error: 'Field phải là "available" hoặc "hidden", value phải là boolean' },
      { status: 400 },
    )
  }

  const existing = await prisma.menuItem.findUnique({ where: { id } })
  if (!existing) {
    return NextResponse.json({ error: 'Món không tồn tại' }, { status: 404 })
  }

  try {
    const item = await prisma.menuItem.update({
      where: { id },
      data: { [field]: value },
    })
    console.log(`[PATCH /api/admin/menu/${id}] Toggled ${field}=${value} for: ${item.name}`)
    return NextResponse.json({ item })
  } catch (error) {
    console.error(`[PATCH /api/admin/menu/${id}] Failed to toggle:`, error)
    return NextResponse.json(
      { error: 'Không thể cập nhật món. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * DELETE /api/admin/menu/[id]
 *
 * Soft-delete: sets hidden=true. Convenience alias for PATCH hidden=true.
 */
export async function DELETE(_request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)
  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID không hợp lệ' }, { status: 400 })
  }

  const existing = await prisma.menuItem.findUnique({ where: { id } })
  if (!existing) {
    return NextResponse.json({ error: 'Món không tồn tại' }, { status: 404 })
  }

  try {
    const item = await prisma.menuItem.update({
      where: { id },
      data: { hidden: true },
    })
    console.log(`[DELETE /api/admin/menu/${id}] Soft-deleted menu item: ${item.name}`)
    return NextResponse.json({ item })
  } catch (error) {
    console.error(`[DELETE /api/admin/menu/${id}] Failed to soft-delete:`, error)
    return NextResponse.json(
      { error: 'Không thể xoá món. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { broadcast } from '@/lib/sse'

type OrderItemInput = {
  menuItemId: number
  quantity: number
  notes?: string
}

type OrderRequestBody = {
  tableId: number
  items: OrderItemInput[]
}

export async function POST(request: NextRequest) {
  // ─── Parse body ───────────────────────────────────────────────────
  let body: OrderRequestBody
  try {
    body = await request.json()
  } catch {
    return NextResponse.json(
      { error: 'Dữ liệu không hợp lệ.' },
      { status: 400 },
    )
  }

  const { tableId, items } = body

  // ─── Validate shape ───────────────────────────────────────────────
  if (
    typeof tableId !== 'number' ||
    !Array.isArray(items) ||
    items.length === 0
  ) {
    return NextResponse.json(
      { error: 'Dữ liệu đơn hàng không hợp lệ.' },
      { status: 400 },
    )
  }

  // ─── Validate quantities ──────────────────────────────────────────
  for (const item of items) {
    if (
      typeof item.menuItemId !== 'number' ||
      typeof item.quantity !== 'number' ||
      !Number.isInteger(item.quantity) ||
      item.quantity <= 0
    ) {
      return NextResponse.json(
        { error: 'Số lượng phải là số nguyên dương.' },
        { status: 400 },
      )
    }
  }

  // ─── Validate table exists ────────────────────────────────────────
  const table = await prisma.table.findUnique({ where: { id: tableId } })
  if (!table) {
    return NextResponse.json(
      { error: 'Bàn không tồn tại.' },
      { status: 404 },
    )
  }

  // ─── Validate menu items exist and are available ──────────────────
  const menuItemIds = items.map((i) => i.menuItemId)
  const menuItems = await prisma.menuItem.findMany({
    where: { id: { in: menuItemIds } },
  })

  const menuItemMap = new Map(menuItems.map((mi) => [mi.id, mi]))

  // Check for missing items
  const missingIds = menuItemIds.filter((id) => !menuItemMap.has(id))
  if (missingIds.length > 0) {
    return NextResponse.json(
      { error: 'Một số món không tồn tại.', missingItems: missingIds },
      { status: 400 },
    )
  }

  // Check for hidden items (soft-deleted)
  const hiddenItems = items
    .filter((i) => {
      const mi = menuItemMap.get(i.menuItemId)
      return mi && mi.hidden
    })
    .map((i) => i.menuItemId)

  if (hiddenItems.length > 0) {
    return NextResponse.json(
      { error: 'Món này không còn trong thực đơn', hiddenItems },
      { status: 400 },
    )
  }

  // Check for unavailable items
  const unavailableItems = items
    .filter((i) => {
      const mi = menuItemMap.get(i.menuItemId)
      return mi && !mi.available
    })
    .map((i) => i.menuItemId)

  if (unavailableItems.length > 0) {
    return NextResponse.json(
      { error: 'Một số món đã hết hàng', unavailableItems },
      { status: 409 },
    )
  }

  // ─── Compute totalAmount server-side ──────────────────────────────
  const totalAmount = items.reduce((sum, item) => {
    const menuItem = menuItemMap.get(item.menuItemId)!
    return sum + menuItem.price * item.quantity
  }, 0)

  // ─── Create Order + OrderItems in transaction ─────────────────────
  try {
    const order = await prisma.$transaction(async (tx) => {
      const newOrder = await tx.order.create({
        data: {
          tableId,
          totalAmount,
          status: 'PENDING',
